import{_ as e,o as a,c as s,ag as n}from"./chunks/framework.DFmy_ALI.js";const u=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),o={name:"guide/introduction.md"};function r(i,t,d,c,l,p){return a(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p><strong>Astro</strong> is Neptune Fintech&#39;s OpenWave-compliant gateway. The SDKs in this documentation let you integrate payments, subscriptions, Open Banking consent, NPT identity resolution, and signed webhooks into any platform.</p><p>Astro follows one rule for secure integrations: <strong>sensitive operations start on your backend and customer authorization happens in Astro-hosted UI or SDK-controlled webviews.</strong> Merchants should never collect bank OTPs, push approval tokens, or Open Banking consent decisions directly inside their own pages.</p><section class="astro-architecture-board astro-doc-demo" aria-label="Animated Astro SDK ownership boundaries"><div class="astro-suite-head"><p class="astro-eyebrow">Ownership boundaries</p><h2>Server SDKs create intent. Client SDKs open secure authorization. Astro signs the outcome.</h2><p>This is the contract every SDK follows across web, React, Flutter, Kotlin, and Swift integrations.</p></div><div class="astro-system-map" aria-hidden="true"><div class="astro-map-node astro-map-server"><b>Backend SDK</b><small>merchant key stays here</small></div><div class="astro-map-node astro-map-sdk"><b>Client SDK</b><small>hosted checkout / consent</small></div><div class="astro-map-node astro-map-astro"><b>Astro</b><small>session, SCA, mandate, OB</small></div><div class="astro-map-node astro-map-identity"><b>Identity</b><small>NPT resolution</small></div><div class="astro-map-node astro-map-bank"><b>Bank</b><small>OTP / push / CBS</small></div><div class="astro-map-node astro-map-merchant"><b>Fulfilment</b><small>after signed webhook</small></div><span class="astro-data-line astro-data-create"><i></i><em>intent</em></span><span class="astro-data-line astro-data-open"><i></i><em>authorize</em></span><span class="astro-data-line astro-data-id"><i></i><em>alias</em></span><span class="astro-data-line astro-data-bank"><i></i><em>bank SCA</em></span><span class="astro-data-line astro-data-webhook"><i></i><em>final event</em></span></div></section><h2 id="sdk-matrix" tabindex="-1">SDK Matrix <a class="header-anchor" href="#sdk-matrix" aria-label="Permalink to &quot;SDK Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>SDK</th><th>Package / Module</th><th>Runtime</th><th>Install</th></tr></thead><tbody><tr><td>TypeScript</td><td><code>@neptune.fintech/astro-sdk</code></td><td>Node.js 18+</td><td><code>npm i @neptune.fintech/astro-sdk</code></td></tr><tr><td>Web Drop-in</td><td><code>@neptune.fintech/astro-web</code></td><td>Browser</td><td>CDN or <code>npm i @neptune.fintech/astro-web</code></td></tr><tr><td>React</td><td><code>@neptune.fintech/astro-react</code></td><td>React 18+</td><td><code>npm i @neptune.fintech/astro-react</code></td></tr><tr><td>Flutter</td><td><code>astro_sdk</code></td><td>Flutter 3.10+ / Dart 3+</td><td><code>pubspec.yaml</code></td></tr><tr><td>Kotlin</td><td><code>ly.neptune.astro:astro-kotlin</code></td><td>JVM 17+</td><td><code>build.gradle.kts</code></td></tr><tr><td>Swift</td><td><code>AstroSDK</code></td><td>iOS 15+ / macOS 12+</td><td>Swift Package Manager</td></tr></tbody></table><h2 id="choose-the-right-sdk" tabindex="-1">Choose the right SDK <a class="header-anchor" href="#choose-the-right-sdk" aria-label="Permalink to &quot;Choose the right SDK&quot;">​</a></h2><ul><li><strong>Backend / server-side</strong> — Use <strong>TypeScript</strong> (Node) or <strong>Kotlin</strong> (JVM/Spring)</li><li><strong>Checkout widget</strong> — Use <strong>Web Drop-in</strong> (no framework) or <strong>React</strong> (React app)</li><li><strong>Mobile app</strong> — Use <strong>Flutter</strong> (cross-platform) or <strong>Swift</strong> (iOS native)</li></ul><h2 id="what-each-sdk-owns" tabindex="-1">What each SDK owns <a class="header-anchor" href="#what-each-sdk-owns" aria-label="Permalink to &quot;What each SDK owns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Surface</th><th>SDK</th><th>What it should do</th><th>What it must not do</th></tr></thead><tbody><tr><td>Merchant backend</td><td>TypeScript / Kotlin</td><td>Create sessions, mandates, OB consent requests, verify webhooks</td><td>Expose merchant keys to browsers</td></tr><tr><td>Web checkout</td><td>Web Drop-in / React</td><td>Open Astro hosted checkout and return success/failure callbacks</td><td>Collect customer OTP directly in merchant UI</td></tr><tr><td>Mobile checkout</td><td>Flutter / Swift</td><td>Launch secure webview or native wrapper around Astro authorization</td><td>Store merchant keys in the app</td></tr><tr><td>Open Banking</td><td>TypeScript backend + hosted consent</td><td>Create PKCE consent, exchange code, call accounts/balances/transactions APIs</td><td>Request broad scopes without clear customer disclosure</td></tr></tbody></table><h2 id="core-flow" tabindex="-1">Core Flow <a class="header-anchor" href="#core-flow" aria-label="Permalink to &quot;Core Flow&quot;">​</a></h2><section class="astro-flow-card astro-checkout-demo astro-doc-demo" aria-label="Animated SDK checkout ownership explainer"><div><p class="astro-flow-kicker">Secure checkout model</p><h3>The merchant starts the session. Astro hosts the customer decision.</h3></div><div class="astro-stage-row"><span style="--i:0;"><b>1</b>Backend creates session</span><span style="--i:1;"><b>2</b>SDK opens hosted UI</span><span style="--i:2;"><b>3</b>Customer uses bank SCA</span><span style="--i:3;"><b>4</b>Astro signs outcome</span><span style="--i:4;"><b>5</b>Merchant fulfils</span></div><div class="astro-browser-board" aria-hidden="true"><div class="astro-code-pane"><b>Backend SDK</b><code>createSession()</code><small>Safe place for merchant keys.</small></div><div class="astro-hosted-pane"><b>Hosted surface</b><span>Checkout</span><span>Consent</span><span>Mandate approval</span></div><div class="astro-result-pane"><b>Webhook</b><code>payment.completed</code><small>Final state only.</small></div></div></section><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Merchant backend creates a PaymentSession   →  POST /payments/sessions</span></span>
<span class="line"><span>2. Customer is redirected to checkoutUrl       →  Astro checkout UI</span></span>
<span class="line"><span>3. Customer authenticates in hosted UI         →  Bank OTP or push SCA</span></span>
<span class="line"><span>4. Astro fires payment.completed webhook       →  Your webhook endpoint</span></span>
<span class="line"><span>5. Merchant fulfils the order                  →  Done ✅</span></span></code></pre></div><h2 id="open-banking-flow" tabindex="-1">Open Banking flow <a class="header-anchor" href="#open-banking-flow" aria-label="Permalink to &quot;Open Banking flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Your backend creates a consent request with scopes + PKCE</span></span>
<span class="line"><span>2. Customer is redirected to Astro hosted consent</span></span>
<span class="line"><span>3. Astro shows the TPP, bank, accounts, and requested permissions</span></span>
<span class="line"><span>4. Customer approves with OTP or push SCA</span></span>
<span class="line"><span>5. Your backend exchanges the code for tokens</span></span>
<span class="line"><span>6. Your backend calls accounts, balances, and transactions APIs</span></span></code></pre></div><h2 id="gateway-url" tabindex="-1">Gateway URL <a class="header-anchor" href="#gateway-url" aria-label="Permalink to &quot;Gateway URL&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Base URL: https://astro.neptune.ly/api/v1</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/astro-sdk/guide/authentication.html">Authentication →</a></li><li><a href="/astro-sdk/sdks/typescript.html">TypeScript SDK →</a></li><li><a href="/astro-sdk/sdks/flutter.html">Flutter SDK →</a></li></ul>`,19)])])}const b=e(o,[["render",r]]);export{u as __pageData,b as default};
